const enabled = $env.N8N_WORKFLOW_PROVIDER_HEALTH_ENABLED;
if (enabled === 'false' || enabled === '0') {
  return [{ json: { killed: true, reason: 'kill_switch_disabled' } }];
}
const requestId = 'ops-provider-health-' + Date.now() + '-' + Math.random().toString(36).slice(2, 8);
const correlationId = 'n8n-provider-health-' + new Date().toISOString().slice(0, 16);
const crypto = require('crypto');
const payloadHash = crypto.createHash('sha256').update(JSON.stringify({ action: 'ops.provider_health_check', ts: new Date().toISOString().slice(0, 16) })).digest('hex');
const idempotencyKey = crypto.createHash('sha256').update(requestId + 'ops.provider_health_check' + payloadHash).digest('hex');
return [{ json: { killed: false, requestId, correlationId, idempotencyKey, timestamp: new Date().toISOString() } }];

const rawItems = $input.all().map((item) => item.json || {});
const rows = Array.isArray(rawItems[0]) ? rawItems[0] : rawItems;
const explicitMonitored = ($env.ASPIRE_PROVIDER_MONITOR_LIST || '').split(',').map((value) => value.trim().toLowerCase()).filter(Boolean);
const requireRecent = ['true', '1', 'yes'].includes(String($env.ASPIRE_PROVIDER_REQUIRE_RECENT || 'false').toLowerCase());
const providersMap = new Map();
const windowStart = Date.now() - (24 * 60 * 60 * 1000);
const dataRows = rows.filter((row) => {
  if (!row || typeof row !== 'object' || Array.isArray(row) || !(row.external_provider || row.provider)) {
    return false;
  }
  const started = Date.parse(row.started_at || row.created_at || '');
  return Number.isFinite(started) && started >= windowStart;
});
const derivedMonitored = [...new Set(dataRows.map((row) => String(row.external_provider || row.provider || 'unknown').trim().toLowerCase()).filter(Boolean))];
const monitored = explicitMonitored.length > 0 ? explicitMonitored : derivedMonitored;
for (const name of monitored) {
  providersMap.set(name, {
    provider: name,
    totalCalls: 0,
    failedCalls: 0,
    avgLatencyMs: 0,
    healthStatus: 'no_data',
    lastSeen: null,
    lastSuccessfulCall: null,
  });
}
for (const row of dataRows) {
  const name = String(row.external_provider || row.provider || 'unknown').trim().toLowerCase();
  if (!providersMap.has(name)) {
    providersMap.set(name, {
      provider: name,
      totalCalls: 0,
      failedCalls: 0,
      avgLatencyMs: 0,
      healthStatus: 'no_data',
      lastSeen: null,
      lastSuccessfulCall: null,
    });
  }
  const entry = providersMap.get(name);
  entry.totalCalls += 1;
  const status = String(row.status || '').toLowerCase();
  if (['failed', 'partial', 'canceled', 'error'].includes(status)) {
    entry.failedCalls += 1;
  }
  const started = Date.parse(row.started_at || row.created_at || '');
  const completed = Date.parse(row.completed_at || row.finished_at || row.created_at || '');
  if (Number.isFinite(started) && Number.isFinite(completed) && completed >= started) {
    const latency = completed - started;
    const previousCount = Math.max(entry.totalCalls - 1, 0);
    entry.avgLatencyMs = Math.round(((entry.avgLatencyMs * previousCount) + latency) / entry.totalCalls);
  }
  entry.lastSeen = row.started_at || row.created_at || entry.lastSeen;
  if (status === 'success') {
    entry.lastSuccessfulCall = row.completed_at || row.finished_at || row.started_at || row.created_at || entry.lastSuccessfulCall;
  }
}
const providers = Array.from(providersMap.values()).map((entry) => {
  if (entry.totalCalls === 0) {
    entry.healthStatus = 'no_data';
    entry.errorRate = 0;
    return entry;
  }
  entry.errorRate = Math.round((entry.failedCalls / entry.totalCalls) * 10000) / 100;
  if (entry.errorRate >= 50) {
    entry.healthStatus = 'disconnected';
  } else if (entry.errorRate > 0) {
    entry.healthStatus = 'degraded';
  } else {
    entry.healthStatus = 'connected';
  }
  return entry;
});
const disconnected = providers.filter((entry) => entry.healthStatus === 'disconnected');
const degraded = providers.filter((entry) => entry.healthStatus === 'degraded');
const noData = providers.filter((entry) => entry.healthStatus === 'no_data');
let overallStatus = 'passed';
let summary = '';
if (disconnected.length > 0) {
  overallStatus = 'failed';
  summary = `Disconnected providers detected (${disconnected.map((entry) => entry.provider).join(', ')})`;
} else if (degraded.length > 0) {
  overallStatus = 'partial';
  summary = `Provider health degraded (${degraded.map((entry) => `${entry.provider}:${entry.errorRate}%`).join(', ')})`;
} else if (providers.length === 0) {
  summary = 'No recent provider traffic in last 24h';
} else if (noData.length > 0 && requireRecent) {
  overallStatus = 'partial';
  summary = `Missing recent provider traffic (${noData.map((entry) => entry.provider).join(', ')})`;
} else if (noData.length > 0) {
  summary = `No provider errors detected; idle providers (${noData.map((entry) => entry.provider).join(', ')})`;
} else {
  summary = `All monitored providers healthy (${providers.length} providers)`;
}
return [{ json: { overallStatus, summary, providers, source: 'provider_call_log', queriedRows: dataRows.length, requireRecent, explicitMonitorCount: explicitMonitored.length } }];

const crypto = require('crypto');
const prep = $('Kill Switch + Prep').first().json;
const payload = {
  id: prep.requestId,
  env: $env.ASPIRE_ROBOT_ENV || 'production',
  suite: $env.ASPIRE_ROBOT_SUITE || 'aspire_robots',
  status: $json.overallStatus || 'partial',
  startedAt: prep.timestamp || new Date().toISOString(),
  finishedAt: new Date().toISOString(),
  versionRef: ($env.ASPIRE_ROBOT_VERSION_REF || 'n8n-live') + ':provider-health',
  summary: $json.summary || 'Provider health workflow completed',
  scenarios: [{
    name: 'provider_health',
    status: $json.overallStatus || 'partial',
    summary: $json.summary || 'Provider health workflow completed',
    evidence: [
      `correlation:${prep.correlationId}`,
      `providers:${($json.providers || []).length}`,
      `invalid_source:${Boolean($json.invalidSource)}`
    ]
  }],
  meta: { workflow: 'provider-health', correlationId: prep.correlationId, requestId: prep.requestId, invalidSource: Boolean($json.invalidSource), providers: $json.providers || [] }
};
const robotBody = JSON.stringify(payload);
const robotSignature = crypto.createHmac('sha256', $env.ASPIRE_ROBOT_S2S_SECRET).update(robotBody).digest('hex');
return [{ json: { ...$json, robotBody, robotSignature } }];

